import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';

export default function Modal({ open, onClose, title, children }) {
  if (!open) return null;
  return (
    <AnimatePresence>
      <div className="fixed inset-0 bg-neutral-900/30 backdrop-blur-sm z-50 flex items-center justify-center p-4">
        <motion.div
          initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
          className="bg-white w-full max-w-md rounded-xl p-6 shadow-2xl relative border border-neutral-200"
        >
          <button onClick={onClose} className="absolute top-4 right-4 text-neutral-400 hover:text-neutral-900 transition-colors">
            <X size={18} />
          </button>
          {title && <h3 className="font-semibold text-lg text-neutral-900 mb-5">{title}</h3>}
          {children}
        </motion.div>
      </div>
    </AnimatePresence>
  );
}

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, AlertTriangle, X } from 'lucide-react';

export default function Toast({ toast, onClose }) {
  return (
    <AnimatePresence>
      {toast && (
        <motion.div
          initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }}
          className="fixed top-5 right-5 z-[100] flex items-start gap-3 bg-white border border-neutral-200 p-4 rounded-xl shadow-lg min-w-[260px]"
        >
          {toast.type === 'error'
            ? <AlertTriangle className="text-danger-500 shrink-0 mt-0.5" size={18} />
            : <CheckCircle2 className="text-success-500 shrink-0 mt-0.5" size={18} />}
          <div className="flex-1">
            <h4 className="font-semibold text-neutral-900 text-sm">{toast.title || (toast.type === 'error' ? 'Error' : 'Berhasil!')}</h4>
            <p className="text-xs text-neutral-500">{toast.message}</p>
          </div>
          {onClose && (
            <button onClick={onClose} className="text-neutral-300 hover:text-neutral-900 transition-colors">
              <X size={14} />
            </button>
          )}
        </motion.div>
      )}
    </AnimatePresence>
  );
}

/* ═══════════════════════════════════════════════════
   HOOK — src/hooks/useCart.js
   Semua logika state keranjang belanja.
   ═══════════════════════════════════════════════════ */

import { useState, useEffect } from 'react';
import { S, fmt } from '../lib/store';

export function useCart() {
    const [cart, setCart] = useState([]);
    const [cartOpen, setCartOpen] = useState(false);

    // Auto-tutup sheet jika keranjang kosong
    useEffect(() => {
        if (cart.length === 0) setCartOpen(false);
    }, [cart]);

    const addToCart = (prod) =>
        setCart(prev => [...prev, { ...prod, qty: 1 }]);

    const updateQty = (id, delta) =>
        setCart(prev =>
            prev
                .map(i => i.id_produk === id ? { ...i, qty: i.qty + delta } : i)
                .filter(i => i.qty > 0)
        );

    const totalItems = cart.reduce((a, i) => a + i.qty, 0);
    const totalPrice = cart.reduce((a, i) => a + i.harga * i.qty, 0);

    const checkoutWA = () => {
        let t = `Halo Admin *${S.nama_toko}*! Saya ingin memesan:\n\n`;
        cart.forEach(i => {
            t += `▪️ ${i.qty}x ${i.nama_produk} - Rp ${fmt(i.harga * i.qty)}\n`;
        });
        t += `\n*Total: Rp ${fmt(totalPrice)}*\n\nMohon diproses ya kak!`;
        window.open(`https://wa.me/${S.wa_num}?text=${encodeURIComponent(t)}`, '_blank');
    };

    return { cart, cartOpen, setCartOpen, addToCart, updateQty, totalItems, totalPrice, checkoutWA };
}

import React, { lazy, Suspense } from 'react'
import ReactDOM from 'react-dom/client'
import './index.css'

// Lazy-loaded page components — only the active page is downloaded
const StorefrontPage = lazy(() => import('./pages/storefront/StorefrontPage'))
const AdminPage      = lazy(() => import('./pages/admin/AdminPage'))
const MasterPage     = lazy(() => import('./pages/master/MasterPage'))
const LoginPage      = lazy(() => import('./pages/login/LoginPage'))

// Minimal loading fallback
function Loading() {
  return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'100vh', fontFamily:'Inter,sans-serif', color:'#a3a3a3' }}>
      <div style={{ textAlign:'center' }}>
        <div style={{ width:32, height:32, border:'3px solid #e5e5e5', borderTop:'3px solid #171717', borderRadius:'50%', animation:'spin 0.6s linear infinite', margin:'0 auto 12px' }} />
        <p style={{ fontSize:13 }}>Memuat...</p>
      </div>
      <style>{`@keyframes spin { to { transform: rotate(360deg) } }`}</style>
    </div>
  )
}

const root = document.getElementById('root')

if (root) {
  let App

  if (window.LOGIN_DATA)       App = LoginPage
  else if (window.MASTER_DATA) App = MasterPage
  else if (window.ADMIN_DATA)  App = AdminPage
  else                         App = StorefrontPage

  ReactDOM.createRoot(root).render(
    <React.StrictMode>
      <Suspense fallback={<Loading />}>
        <App />
      </Suspense>
    </React.StrictMode>
  )
}

